(1, 1, 'Комментатор WordPress', 'wapuu@wordpress.example', 'https://ru.wordpress.org/', '', '2026-03-23 10:01:11', '2026-03-23 07:01:11', 'Привет! Это комментарий.\nЧтобы начать модерировать, редактировать и удалять комментарии, перейдите на экран «Комментарии» в консоли.\nАватары авторов комментариев загружаются с сервиса <a href=\"https://ru.gravatar.com/\">Gravatar</a>.', 0, 'post-trashed', '', 'comment', 0, 0),
(2, 95, 'Reo', 'bombarkdn@gmail.com', 'http://mysite1.rus', '127.0.0.1', '2026-03-25 10:33:44', '2026-03-25 07:33:44', 'sadsd', 0, '1', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/146.0.0.0 Safari/537.36 Edg/146.0.0.0', 'comment', 0, 1),
(3, 130, 'WooCommerce', 'woocommerce@mysite1.rus', '', '', '2026-04-01 11:27:51', '2026-04-01 08:27:51', 'Оплата завершена.', 0, '1', 'WooCommerce', 'order_note', 0, 0),
(4, 154, 'WooCommerce', 'woocommerce@mysite1.rus', '', '', '2026-04-01 13:25:50', '2026-04-01 10:25:50', 'Оплата по факту доставки. Статус заказа изменён с «Ожидается оплата» на «Обработка».', 0, '1', 'WooCommerce', 'order_note', 0, 0);
