ock-column is-vertically-aligned-center\" style=\"flex-basis:33.33%\"><!-- wp:paragraph {\"align\":\"left\",\"style\":{\"layout\":{\"selfStretch\":\"fixed\",\"flexSize\":\"70%\"}}} -->\n<p class=\"has-text-align-left\">Мы преданы искусству ремесла, где каждая ваза тщательно создается до совершенства. Наша страсть к деталям и приверженность качеству проявляются в каждом изделии, в результате чего вазы являются не просто функциональными, а настоящими произведениями искусства.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns -->\n\n<!-- wp:spacer {\"height\":\"var:preset|spacing|20\"} -->\n<div style=\"height:var(--wp--preset--spacing--20)\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n<!-- /wp:spacer -->\n\n<!-- wp:group {\"align\":\"wide\",\"style\":{\"spacing\":{\"blockGap\":\"var:preset|spacing|30\"}},\"layout\":{\"type\":\"flex\",\"flexWrap\":\"nowrap\",\"verticalAlignment\":\"top\"}} -->\n<div class=\"wp-block-group alignwide\"><!-- wp:image {\"id\":266,\"aspectRatio\":\"2/3\",\"scale\":\"cover\",\"sizeSlug\":\"full\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image size-full\"><img src=\"https://s1.wp.com/i/woo-block-patterns/2024/07/a0c4b80dc701de6a1143de003da3ef95-1.jpeg\" alt=\"\" class=\"wp-image-266\" style=\"aspect-ratio:2/3;object-fit:cover\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:image {\"id\":62,\"aspectRatio\":\"2/3\",\"scale\":\"cover\",\"sizeSlug\":\"full\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image size-full\"><img src=\"https://s2.wp.com/i/woo-block-patterns/2024/06/plant-white-leaf-flower-vase-green.jpg\" alt=\"\" class=\"wp-image-62\" style=\"aspect-ratio:2/3;object-fit:cover\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:image {\"id\":69,\"aspectRatio\":\"2/3\",\"scale\":\"cover\",\"sizeSlug\":\"full\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image size-full\"><img src=\"https://s1.wp.com/i/woo-block-patterns/2024/06/tree-branch-plant-wood-leaf-flo