ap\":\"8px\",\"padding\":{\"top\":\"0px\",\"right\":\"0px\",\"bottom\":\"0px\",\"left\":\"0px\"},\"margin\":{\"top\":\"2px\",\"bottom\":\"0px\"}}},\"layout\":{\"type\":\"flex\",\"flexWrap\":\"nowrap\"}} -->\n<div class=\"wp-block-group\" style=\"margin-top:2px;margin-bottom:0px;padding-top:0px;padding-right:0px;padding-bottom:0px;padding-left:0px\"><!-- wp:paragraph {\"style\":{\"typography\":{\"fontSize\":\"1.2em\"},\"color\":{\"text\":\"#000000\"}}} -->\n<p class=\"has-text-color\" style=\"color:#000000;font-size:1.2em\"><strong><sup><sub>$</sub></sup>158.99</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"style\":{\"typography\":{\"fontSize\":\"0.7em\"},\"layout\":{\"selfStretch\":\"fit\",\"flexSize\":null},\"color\":{\"text\":\"#000000\"}}} -->\n<p class=\"has-text-color\" style=\"color:#000000;font-size:0.7em\"><s>было $173.99</s></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"style\":{\"typography\":{\"fontSize\":\"0.7em\"},\"color\":{\"text\":\"#C51313\"}}} -->\n<p class=\"has-text-color\" style=\"color:#C51313;font-size:0.7em\"><strong>9% скидка</strong></p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"style\":{\"spacing\":{\"blockGap\":\"0px\",\"margin\":{\"top\":\"5px\"}}},\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group\" style=\"margin-top:5px\"><!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"#00A510\"},\"typography\":{\"fontSize\":\"0.7em\"},\"spacing\":{\"margin\":{\"top\":\"0px\",\"right\":\"0px\",\"bottom\":\"0px\",\"left\":\"0px\"}}}} -->\n<p class=\"has-text-color\" style=\"color:#00A510;margin-top:0px;margin-right:0px;margin-bottom:0px;margin-left:0px;font-size:0.7em\"><strong>Бесплатная доставка за 2 дня</strong></p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"layout\":{\"type\":\"constrained\",\"justifyContent\":\"left\"}} -->\n<div class=\"wp-block-group\"><!-- wp:paragraph {\"style\":{\"typography\":{\"fontSize\":\"0.8em\"},\"color\":{\"text\":\"#000000\"}}} -->\n<p class=\"has-text-color\" style=\"color:#000000;font-size:0.8em\">Диван «Современная элегантность: роскошный обитый угольный серый» гармонирует со стилем и комфортом, чтобы переосмыслить ваше жилое пространство. Этот потрясающий предмет изготовлен с мягкими подушками из высокоплотной пены, обтянутыми богатой угольной серой тканью, которая приятно мягкая на ощупь. Его чистые линии и современный силуэт дополняются прочной деревянной рамой, что делает его долговечным и стильным дополнением к любому интерьеру. Будь то отдых или прием гостей, этот диван обещает непревзойденный комфорт и безупречно шикарный вид.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"layout\":{\"type\":\"constrained\",\"justifyContent\":\"left\"}} -->\n<div class=\"wp-block-group\"><!-- wp:buttons -->\n<div class=\"wp-block-buttons\"><!-- wp:button {\"style\":{\"color\":{\"text\":\"#ffffff\",\"background\":\"#000000\"}}} --><div class=\"wp-block-button\"><a class=\"wp-block-button__link has-text-color has-background wp-element-button\" style=\"color:#ffffff;background-color:#000000\">В корзину</a></div><!-- /wp:button --></div>\n<!-- /wp:buttons --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"layout\":{\"type\":\"constrained\",\"justifyContent\":\"left\"}} -->\n<div class=\"wp-block-group\"><!-- wp:paragraph {\"style\":{\"typography\":{\"fontSize\":\"0.8em\"},\"color\":{\"text\":\"#000000\"}}} -->\n<p class=\"has-text-color\" style=\"color:#000000;font-size:0.8em\"><strong>Функции</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list {\"style\":{\"spacing\":{\"margin\":{\"top\":\"10px\",\"right\":\"0\",\"bottom\":\"0\",\"left\":\"0\"}},\"color\":{\"text\":\"#000000\"}},\"className\":\"has-foreground-color\"} -->\n<ul style=\"color:#000000;margin-top:10px;margin-right:0;margin-bottom:0;margin-left:0\" class=\"wp-block-list has-foreground-color has-text-color\"><!-- wp:list-item {\"style\":{\"typography\":{\"fontSize\":\"0.8em\"}}} -->\n<li style=\"font-si